script:
# fin_sight_dashboard_api
# Script Type: API
# API Method: fin_sight_dashboard_api
# Enhanced with proper account hierarchy: Root Type → Account Type → Parent Account → Account Name

err_msg = None
args = frappe.form_dict

def parse_arg(val):
    if val is None:
        return ""
    if isinstance(val, (list, tuple)) and len(val) > 0:
        val = val[0]
    return str(val).strip()

# Optional: Chart of Account CSV for correct Balance Sheet parent-child hierarchy (columns: Report Type, ID, Parent Account)
chart_of_accounts_csv = parse_arg(args.get("chart_of_accounts_csv")) if args.get("chart_of_accounts_csv") else ""
coa_by_id = None
coa_balance_sheet_ids = None

def get_parent_path_from_coa(acc_id):
    """Build path [Level1..Level5, Account Name] from CSV hierarchy (ID, Parent Account). Returns list of 6 elements."""
    if not coa_by_id or not acc_id:
        return None
    path_rev = []
    current = acc_id
    visited = set()
    while current and current not in visited:
        visited.add(current)
        node = coa_by_id.get(current)
        if not node:
            break
        path_rev.append((current, (node.get("account_name") or current)))
        current = (node.get("parent_account") or "").strip()
        if not current:
            break
    path_rev.reverse()
    pad = ["", "", "", "", "", ""]
    for i in range(min(5, len(path_rev))):
        pad[i] = path_rev[i][1]
    if len(path_rev) > 0:
        pad[5] = path_rev[-1][1]
    return pad

from_date = parse_arg(args.get("from_date"))
to_date = parse_arg(args.get("to_date"))
company = parse_arg(args.get("company"))
include_draft = parse_arg(args.get("include_draft"))
format_arg = parse_arg(args.get("format")) or "annual"

if not from_date or not to_date:
    now_str = str(frappe.utils.now())[:10]
    to_date = to_date or now_str
    from_date = from_date or (now_str[:4] + "-01-01")

try:
    from_date = frappe.utils.getdate(from_date).isoformat()
    to_date = frappe.utils.getdate(to_date).isoformat()
except Exception as e:
    err_msg = "Invalid date format. Use YYYY-MM-DD."
    from_date = from_date or "2025-01-01"
    to_date = to_date or "2025-12-31"

try:
    all_month_names = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"]
    month_name_toto_num = {"jan": 1, "feb": 2, "mar": 3, "apr": 4, "may": 5, "jun": 6, "jul": 7, "aug": 8, "sep": 9, "oct": 10, "nov": 11, "dec": 12}

    def month_label(y, m):
        return all_month_names[m - 1] + "-" + str(y)[2:]

    def quarter_label(y, q):
        return "Q" + str(q) + "-" + str(y)[2:]

    s_from = str(from_date or "").strip()
    s_to = str(to_date or "").strip()
    y1 = int(s_from[0:4]) if len(s_from) >= 10 else None
    m1 = int(s_from[5:7]) if len(s_from) >= 10 else None
    y2 = int(s_to[0:4]) if len(s_to) >= 10 else None
    m2 = int(s_to[5:7]) if len(s_to) >= 10 else None

    month_names = []
    if y1 is not None and m1 is not None and y2 is not None and m2 is not None and (y1 < y2 or (y1 == y2 and m1 <= m2)):
        current_y = y1
        current_m = m1
        while current_y < y2 or (current_y == y2 and current_m <= m2):
            month_names = month_names + [month_label(current_y, current_m)]
            current_m = current_m + 1
            if current_m > 12:
                current_m = 1
                current_y = current_y + 1

    quarter_names = []
    if y1 is not None and y2 is not None:
        for yy in range(y1, y2 + 1):
            for q in range(1, 5):
                if yy == y1 and q < (m1 - 1) // 3 + 1:
                    continue
                if yy == y2 and q > (m2 - 1) // 3 + 1:
                    continue
                quarter_names = quarter_names + [quarter_label(yy, q)]

    # Parse Chart of Account CSV for correct Balance Sheet hierarchy (Report Type, ID, Parent Account)
    if chart_of_accounts_csv and isinstance(chart_of_accounts_csv, str) and chart_of_accounts_csv.strip():
        try:
            import csv
            from io import StringIO
            reader = csv.DictReader(StringIO(chart_of_accounts_csv.strip()))
            coa_by_id = {}
            coa_balance_sheet_ids = set()
            for row in reader:
                aid = (row.get("ID") or "").strip()
                if not aid:
                    continue
                parent = (row.get("Parent Account") or "").strip()
                report_type = (row.get("Report Type") or "").strip()
                account_name = (row.get("Account Name") or aid).strip()
                root_type = (row.get("Root Type") or "").strip()
                is_grp = row.get("Is Group") or row.get("is_group") or "0"
                try:
                    is_group_coa = 1 if int(is_grp) else 0
                except Exception:
                    is_group_coa = 0
                sr = row.get("Sr") or row.get("idx") or "0"
                try:
                    idx = int(sr)
                except Exception:
                    idx = 0
                coa_by_id[aid] = {"parent_account": parent, "account_name": account_name, "report_type": report_type, "root_type": root_type, "idx": idx, "is_group": is_group_coa}
                if report_type and "balance" in report_type.lower() and "sheet" in report_type.lower():
                    coa_balance_sheet_ids.add(aid)
        except Exception as coa_csv_err:
            coa_by_id = None
            coa_balance_sheet_ids = None

    # Query with full account details
    monthly_detail_sql = """
    SELECT gl.account, acc.account_name, acc.root_type, acc.parent_account, acc.account_type, acc.is_group, acc.include_in_gross,
        YEAR(gl.posting_date) AS y, MONTH(gl.posting_date) AS m,
        SUM(gl.debit) AS debit, SUM(gl.credit) AS credit
    FROM `tabGL Entry` AS gl
    INNER JOIN `tabAccount` AS acc ON acc.name = gl.account
    WHERE gl.posting_date BETWEEN %(from_date)s AND %(to_date)s
    """
    monthly_params = {"from_date": from_date, "to_date": to_date}
    if company:
        monthly_detail_sql = monthly_detail_sql + " AND gl.company = %(company)s"
        monthly_params["company"] = company
    if include_draft and include_draft.lower() in ("1", "true", "yes", "all"):
        monthly_detail_sql = monthly_detail_sql + " AND gl.docstatus IN (0, 1)"
    else:
        monthly_detail_sql = monthly_detail_sql + " AND gl.docstatus = 1"
    monthly_detail_sql = monthly_detail_sql + " GROUP BY gl.account, acc.account_name, acc.root_type, acc.parent_account, acc.account_type, acc.is_group, acc.include_in_gross, YEAR(gl.posting_date), MONTH(gl.posting_date)"

    opening_sql = """
    SELECT gl.account, SUM(gl.debit) - SUM(gl.credit) AS opening
    FROM `tabGL Entry` AS gl
    WHERE gl.posting_date < %(from_date)s
    """
    opening_params = {"from_date": from_date}
    if company:
        opening_sql = opening_sql + " AND gl.company = %(company)s"
        opening_params["company"] = company
    if include_draft and include_draft.lower() in ("1", "true", "yes", "all"):
        opening_sql = opening_sql + " AND gl.docstatus IN (0, 1)"
    else:
        opening_sql = opening_sql + " AND gl.docstatus = 1"
    opening_sql = opening_sql + " GROUP BY gl.account"

    try:
        monthly_detail_rows = frappe.db.sql(monthly_detail_sql, monthly_params, as_dict=True)
    except Exception as e:
        monthly_detail_rows = []
        err_msg = str(e) if not err_msg else err_msg
    try:
        opening_rows = frappe.db.sql(opening_sql, opening_params, as_dict=True)
    except Exception as e:
        opening_rows = []

    opening_by_account = {}
    for r in opening_rows:
        acc = r.get("account")
        if acc:
            opening_by_account[acc] = float(r.get("opening") or 0)

    account_monthly_data = {}
    for r in monthly_detail_rows:
        acc = r.get("account") or ""
        y = r.get("y") or 2025
        m = r.get("m") or 1
        mn = month_label(y, m)
        if mn not in month_names:
            continue
        if acc not in account_monthly_data:
            account_monthly_data[acc] = {
                "account_name": r.get("account_name") or acc,
                "root_type": r.get("root_type") or "",
                "parent_account": r.get("parent_account") or "",
                "account_type": r.get("account_type") or "",
                "is_group": int(r.get("is_group") or 0),
                "include_in_gross": int(r.get("include_in_gross") or 0),
                "months": {}
            }
        debit = float(r.get("debit") or 0)
        credit = float(r.get("credit") or 0)
        account_monthly_data[acc]["months"][mn] = {
            "debit": debit,
            "credit": credit,
            "balance": debit - credit,
            "pl": credit - debit
        }

    all_account_ids = set(list(opening_by_account.keys()) + list(account_monthly_data.keys()))
    account_ids_needed = set(all_account_ids)
    try:
        all_acc_rows = frappe.get_all("Account", fields=["name", "account_name", "parent_account", "root_type", "account_type", "is_group"], limit_page_length=10000)
    except Exception as e:
        all_acc_rows = []
    all_accounts_map = {}
    for a in all_acc_rows:
        n = a.get("name")
        if n:
            all_accounts_map[n] = {"account_name": a.get("account_name") or n, "parent_account": a.get("parent_account") or "", "root_type": a.get("root_type") or "", "account_type": a.get("account_type") or "", "is_group": a.get("is_group") or 0}

    def get_parent_path(account_name):
        """Build path [Level1, Level2, Level3, Level4, Level5, Account Name] by traversing parent_account (like Account.csv)."""
        path_rev = []
        current = account_name
        visited = set()
        while current and current not in visited:
            visited = visited | {current}
            a = all_accounts_map.get(current)
            aname = (a.get("account_name") or current) if a else current
            path_rev = path_rev + [aname]
            current = (a.get("parent_account") or "") if a else ""
            if not current:
                break
        path_rev.reverse()
        pad = ["", "", "", "", "", ""]
        for i in range(min(5, len(path_rev))):
            pad[i] = path_rev[i]
        if len(path_rev) > 0:
            pad[5] = path_rev[-1]
        return pad

    all_accounts = set(all_account_ids)
    try:
        coa_rows = frappe.get_all("Account", filters={"root_type": ["in", ["Asset", "Liability", "Equity"]]}, fields=["name", "account_name", "parent_account", "root_type", "account_type", "is_group"], limit_page_length=10000)
        for a in (coa_rows or []):
            n = a.get("name")
            if n:
                all_accounts.add(n)
    except Exception as coa_err:
        pass
    accounts_full = []
    for acc in sorted(all_accounts):
        opening = opening_by_account.get(acc, 0)
        info = dict(account_monthly_data.get(acc, {}))
        coa_info = all_accounts_map.get(acc, {})
        if not info.get("account_name"):
            info["account_name"] = coa_info.get("account_name") or acc
        if not info.get("root_type"):
            info["root_type"] = coa_info.get("root_type") or ""
        if not info.get("parent_account") and coa_info.get("parent_account") is not None:
            info["parent_account"] = coa_info.get("parent_account") or ""
        if not info.get("account_type") and coa_info.get("account_type") is not None:
            info["account_type"] = coa_info.get("account_type") or ""
        if "is_group" not in info and "is_group" in coa_info:
            info["is_group"] = coa_info.get("is_group", 0)
        aname = info.get("account_name", acc)
        rtype = info.get("root_type", "")
        parent = info.get("parent_account", "")
        atype = info.get("account_type", "")
        months_data = info.get("months", {})
        period_bal = sum(months_data.get(mn, {}).get("balance", 0) for mn in month_names)
        period_pl = sum(months_data.get(mn, {}).get("pl", 0) for mn in month_names)
        closing = opening + period_bal

        monthly = {}
        for mn in month_names:
            md = months_data.get(mn, {})
            monthly[mn] = {
                "debit": round(md.get("debit", 0), 0),
                "credit": round(md.get("credit", 0), 0),
                "balance": round(md.get("balance", 0), 0),
                "pl": round(md.get("pl", 0), 0)
            }

        quarterly = {}
        for qn in quarter_names:
            quarterly[qn] = {"debit": 0, "credit": 0, "balance": 0, "pl": 0}

        for mn in month_names:
            parts = mn.split("-")
            if len(parts) >= 2:
                mnum = month_name_toto_num.get(parts[0].lower()[:3], 1)
                ynum = 2000 + int(parts[1]) if len(parts[1]) == 2 else int(parts[1])
                q = (mnum - 1) // 3 + 1
                qn = quarter_label(ynum, q)
                if qn in quarterly:
                    quarterly[qn]["debit"] = quarterly[qn]["debit"] + monthly[mn]["debit"]
                    quarterly[qn]["credit"] = quarterly[qn]["credit"] + monthly[mn]["credit"]
                    quarterly[qn]["balance"] = quarterly[qn]["balance"] + monthly[mn]["balance"]
                    quarterly[qn]["pl"] = quarterly[qn]["pl"] + monthly[mn]["pl"]

        row = {
            "account": acc,
            "account_name": aname,
            "root_type": rtype,
            "parent_account": parent,
            "account_type": atype,
            "is_group": info.get("is_group", 0),
            "include_in_gross": info.get("include_in_gross", 0),
            "opening": round(opening, 0),
            "period": round(period_bal, 0),
            "period_pl": round(period_pl, 0),
            "closing": round(closing, 0),
            "monthly": monthly,
            "quarterly": quarterly
        }
        accounts_full = accounts_full + [row]

    def is_direct_expense(acc):
        """Classify so Direct/Indirect match Chart of Accounts: respect account_type and any ancestor's account_type."""
        # 1) If this account's account_type is "Indirect Expense", treat as indirect
        atype_lower = (acc.get("account_type") or "").strip().lower()
        if "indirect" in atype_lower:
            return False
        # 2) If any ancestor (parent, grandparent, ...) has account_type "Indirect Expense", treat as indirect
        current = acc.get("parent_account") or ""
        visited = set()
        while current and current not in visited:
            visited.add(current)
            anc = all_accounts_map.get(current) or {}
            anc_type = (anc.get("account_type") or "").strip().lower()
            if "indirect" in anc_type:
                return False
            current = anc.get("parent_account") or ""
        # 3) If path (by account name) contains any level with "indirect", treat as indirect
        path = get_parent_path(acc.get("account") or "")
        path_lower = [(p or "").lower() for p in (path[:5] if path else [])]
        if any("indirect" in p for p in path_lower):
            return False
        # 4) If account sits under "Direct Expenses" in hierarchy, treat as direct
        if any("direct" in p and "indirect" not in p for p in path_lower):
            return True
        if acc.get("include_in_gross") == 1:
            return True
        if acc.get("include_in_gross") == 0:
            return False
        level2 = (path[1] or "").lower() if len(path) > 1 else ""
        if "direct" in level2:
            return True
        if "indirect" in level2:
            return False
        p = (acc.get("parent_account") or "").lower()
        a = atype_lower
        return any(kw in p for kw in ["direct", "cost of goods", "cogs", "cost of sales", "factory", "purchase", "manufacturing"]) or "direct" in a

    def is_manufacturing_expense(acc):
        path = get_parent_path(acc.get("account") or "")
        path_lower = [(p or "").lower() for p in (path[:5] if path else [])]
        atype_lower = (acc.get("account_type") or "").strip().lower()
        return any(k in " ".join(path_lower) + " " + atype_lower for k in ("manufacturing", "factory", "cogs", "cost of goods", "cost of sales", "production"))

    def is_stock_expense(acc):
        path = get_parent_path(acc.get("account") or "")
        path_lower = [(p or "").lower() for p in (path[:5] if path else [])]
        atype_lower = (acc.get("account_type") or "").strip().lower()
        return any(k in " ".join(path_lower) + " " + atype_lower for k in ("stock", "inventory", "warehouse"))

    def is_administrative_expense(acc):
        path = get_parent_path(acc.get("account") or "")
        path_lower = [(p or "").lower() for p in (path[:5] if path else [])]
        atype_lower = (acc.get("account_type") or "").strip().lower()
        return any(k in " ".join(path_lower) + " " + atype_lower for k in ("administrative", "admin", "general", "office"))

    def is_selling_expense(acc):
        path = get_parent_path(acc.get("account") or "")
        path_lower = [(p or "").lower() for p in (path[:5] if path else [])]
        atype_lower = (acc.get("account_type") or "").strip().lower()
        return any(k in " ".join(path_lower) + " " + atype_lower for k in ("selling", "sales", "distribution", "marketing"))

    income_accounts = [r for r in accounts_full if (r.get("root_type") or "") == "Income"]
    expense_accounts = [r for r in accounts_full if (r.get("root_type") or "") == "Expense"]
    direct_exp = [r for r in expense_accounts if is_direct_expense(r)]
    indirect_exp = [r for r in expense_accounts if not is_direct_expense(r)]
    manufacturing_exp = [r for r in direct_exp if is_manufacturing_expense(r)]
    stock_exp = [r for r in direct_exp if is_stock_expense(r) and not is_manufacturing_expense(r)]
    administrative_exp = [r for r in indirect_exp if is_administrative_expense(r)]
    selling_exp = [r for r in indirect_exp if is_selling_expense(r) and not is_administrative_expense(r)]
    direct_manufacturing_pl = sum(r.get("period_pl", 0) for r in manufacturing_exp)
    direct_stock_pl = sum(r.get("period_pl", 0) for r in stock_exp)
    indirect_administrative_pl = sum(r.get("period_pl", 0) for r in administrative_exp)
    indirect_selling_pl = sum(r.get("period_pl", 0) for r in selling_exp)
    asset_accounts = [r for r in accounts_full if (r.get("root_type") or "") == "Asset"]
    liability_accounts = [r for r in accounts_full if (r.get("root_type") or "") == "Liability"]
    equity_accounts = [r for r in accounts_full if (r.get("root_type") or "") == "Equity"]
    if coa_balance_sheet_ids is not None:
        asset_accounts = [r for r in asset_accounts if r.get("account") in coa_balance_sheet_ids]
        liability_accounts = [r for r in liability_accounts if r.get("account") in coa_balance_sheet_ids]
        equity_accounts = [r for r in equity_accounts if r.get("account") in coa_balance_sheet_ids]

    # Build hierarchical structure: Root Type → Account Type → Parent Account → Account Name
    def build_hierarchy(accounts, root_types):
        """Build 4-level hierarchy: Root Type → Account Type → Parent Account → Account Name"""
        hierarchy = {}

        for acc in accounts:
            if acc.get('is_group'):
                continue
            rt = acc.get("root_type") or "(No Root Type)"
            if rt not in root_types:
                continue

            at = acc.get("account_type") or "(No Account Type)"
            pa = acc.get("parent_account") or "(No Parent)"
            an = acc.get("account_name") or acc.get("account")

            if rt not in hierarchy:
                hierarchy[rt] = {"account_types": {}, "total_pl": 0, "monthly": {}, "quarterly": {}}

            if at not in hierarchy[rt]["account_types"]:
                hierarchy[rt]["account_types"][at] = {"parents": {}, "total_pl": 0, "monthly": {}, "quarterly": {}}

            if pa not in hierarchy[rt]["account_types"][at]["parents"]:
                hierarchy[rt]["account_types"][at]["parents"][pa] = {"accounts": [], "total_pl": 0, "monthly": {}, "quarterly": {}}

            hierarchy[rt]["account_types"][at]["parents"][pa]["accounts"] = (hierarchy[rt]["account_types"][at]["parents"][pa].get("accounts") or []) + [acc]

            # Aggregate values
            pl = acc.get("period_pl", 0)
            hierarchy[rt]["account_types"][at]["parents"][pa]["total_pl"] = hierarchy[rt]["account_types"][at]["parents"][pa]["total_pl"] + pl
            hierarchy[rt]["account_types"][at]["total_pl"] = hierarchy[rt]["account_types"][at]["total_pl"] + pl
            hierarchy[rt]["total_pl"] = hierarchy[rt]["total_pl"] + pl

            for mn in month_names:
                if mn not in hierarchy[rt]["monthly"]:
                    hierarchy[rt]["monthly"][mn] = 0
                if mn not in hierarchy[rt]["account_types"][at]["monthly"]:
                    hierarchy[rt]["account_types"][at]["monthly"][mn] = 0
                if mn not in hierarchy[rt]["account_types"][at]["parents"][pa]["monthly"]:
                    hierarchy[rt]["account_types"][at]["parents"][pa]["monthly"][mn] = 0

                val = acc.get("monthly", {}).get(mn, {}).get("pl", 0)
                hierarchy[rt]["monthly"][mn] = hierarchy[rt]["monthly"][mn] + val
                hierarchy[rt]["account_types"][at]["monthly"][mn] = hierarchy[rt]["account_types"][at]["monthly"][mn] + val
                hierarchy[rt]["account_types"][at]["parents"][pa]["monthly"][mn] = hierarchy[rt]["account_types"][at]["parents"][pa]["monthly"][mn] + val

            for qn in quarter_names:
                if qn not in hierarchy[rt]["quarterly"]:
                    hierarchy[rt]["quarterly"][qn] = 0
                if qn not in hierarchy[rt]["account_types"][at]["quarterly"]:
                    hierarchy[rt]["account_types"][at]["quarterly"][qn] = 0
                if qn not in hierarchy[rt]["account_types"][at]["parents"][pa]["quarterly"]:
                    hierarchy[rt]["account_types"][at]["parents"][pa]["quarterly"][qn] = 0

                val = acc.get("quarterly", {}).get(qn, {}).get("pl", 0)
                hierarchy[rt]["quarterly"][qn] = hierarchy[rt]["quarterly"][qn] + val
                hierarchy[rt]["account_types"][at]["quarterly"][qn] = hierarchy[rt]["account_types"][at]["quarterly"][qn] + val
                hierarchy[rt]["account_types"][at]["parents"][pa]["quarterly"][qn] = hierarchy[rt]["account_types"][at]["parents"][pa]["quarterly"][qn] + val

        return hierarchy

    income_hierarchy = build_hierarchy(income_accounts, ["Income"])
    direct_expense_hierarchy = build_hierarchy(direct_exp, ["Expense"])
    indirect_expense_hierarchy = build_hierarchy(indirect_exp, ["Expense"])
    assets_hierarchy = build_hierarchy(asset_accounts, ["Asset"])
    liabilities_hierarchy = build_hierarchy(liability_accounts, ["Liability"])
    equity_hierarchy = build_hierarchy(equity_accounts, ["Equity"])

    def add_bs_opening_closing(hierarchy):
        """Add opening and closing subtotals to balance sheet hierarchy (all levels)."""
        for rt, rt_data in hierarchy.items():
            rt_opening = 0
            rt_closing = 0
            for at, at_data in (rt_data.get("account_types") or {}).items():
                at_opening = 0
                at_closing = 0
                for pa, pa_data in (at_data.get("parents") or {}).items():
                    pa_opening = sum((acc.get("opening") or 0) for acc in (pa_data.get("accounts") or []))
                    pa_closing = sum((acc.get("closing") or 0) for acc in (pa_data.get("accounts") or []))
                    pa_data["opening"] = round(pa_opening, 0)
                    pa_data["closing"] = round(pa_closing, 0)
                    at_opening = at_opening + pa_opening
                    at_closing = at_closing + pa_closing
                at_data["opening"] = round(at_opening, 0)
                at_data["closing"] = round(at_closing, 0)
                rt_opening = rt_opening + at_opening
                rt_closing = rt_closing + at_closing
            rt_data["opening"] = round(rt_opening, 0)
            rt_data["closing"] = round(rt_closing, 0)
        return hierarchy

    add_bs_opening_closing(assets_hierarchy)
    add_bs_opening_closing(liabilities_hierarchy)
    add_bs_opening_closing(equity_hierarchy)

    def build_5level_hierarchy_rows(accounts, root_types, sign_pl=1):
        """Build flat rows with Parent Level 1..5, Account Name, Amount, monthly, quarterly. All parent levels show aggregated value (subtotal)."""
        agg = {}
        detail_rows = []
        for acc in accounts:
            if acc.get('is_group'):
                continue
            rt = acc.get("root_type") or ""
            if rt not in root_types:
                continue
            path = get_parent_path(acc.get("account") or "")
            l1 = path[0] or rt or "(No Level 1)"
            l2 = path[1] if len(path) > 1 else ""
            l3 = path[2] if len(path) > 2 else ""
            l4 = path[3] if len(path) > 3 else ""
            l5 = path[4] if len(path) > 4 else ""
            aname = path[5] if (len(path) > 5 and path[5]) else (acc.get("account_name") or acc.get("account"))
            amt = sign_pl * (acc.get("period_pl") or 0)
            monthly = acc.get("monthly", {})
            quarterly = acc.get("quarterly", {})
            detail_rows = detail_rows + [{"level1": l1, "level2": l2, "level3": l3, "level4": l4, "level5": l5, "account_name": aname, "amount": amt, "monthly": monthly, "quarterly": quarterly, "is_subtotal": False}]
            key1 = (l1,)
            key2 = (l1, l2)
            key3 = (l1, l2, l3)
            key4 = (l1, l2, l3, l4)
            key5 = (l1, l2, l3, l4, l5)
            if key1 not in agg:
                agg[key1] = {"amount": 0, "monthly": {mn: 0 for mn in month_names}, "quarterly": {qn: 0 for qn in quarter_names}}
            if key2 not in agg:
                agg[key2] = {"amount": 0, "monthly": {mn: 0 for mn in month_names}, "quarterly": {qn: 0 for qn in quarter_names}}
            if key3 not in agg:
                agg[key3] = {"amount": 0, "monthly": {mn: 0 for mn in month_names}, "quarterly": {qn: 0 for qn in quarter_names}}
            if key4 not in agg:
                agg[key4] = {"amount": 0, "monthly": {mn: 0 for mn in month_names}, "quarterly": {qn: 0 for qn in quarter_names}}
            if key5 not in agg:
                agg[key5] = {"amount": 0, "monthly": {mn: 0 for mn in month_names}, "quarterly": {qn: 0 for qn in quarter_names}}
            agg[key1]["amount"] = agg[key1]["amount"] + amt
            agg[key2]["amount"] = agg[key2]["amount"] + amt
            agg[key3]["amount"] = agg[key3]["amount"] + amt
            agg[key4]["amount"] = agg[key4]["amount"] + amt
            agg[key5]["amount"] = agg[key5]["amount"] + amt
            for mn in month_names:
                v = sign_pl * (monthly.get(mn, {}).get("pl", 0))
                agg[key1]["monthly"][mn] = agg[key1]["monthly"][mn] + v
                agg[key2]["monthly"][mn] = agg[key2]["monthly"][mn] + v
                agg[key3]["monthly"][mn] = agg[key3]["monthly"][mn] + v
                agg[key4]["monthly"][mn] = agg[key4]["monthly"][mn] + v
                agg[key5]["monthly"][mn] = agg[key5]["monthly"][mn] + v
            for qn in quarter_names:
                v = sign_pl * (quarterly.get(qn, {}).get("pl", 0))
                agg[key1]["quarterly"][qn] = agg[key1]["quarterly"][qn] + v
                agg[key2]["quarterly"][qn] = agg[key2]["quarterly"][qn] + v
                agg[key3]["quarterly"][qn] = agg[key3]["quarterly"][qn] + v
                agg[key4]["quarterly"][qn] = agg[key4]["quarterly"][qn] + v
                agg[key5]["quarterly"][qn] = agg[key5]["quarterly"][qn] + v
        # Merge detail rows that share same (level1..level5, account_name) to avoid duplicate account names
        def merge_period_dict(d1, d2, is_object_val=True):
            out_per = {}
            for k in set((d1 or {}).keys()) | set((d2 or {}).keys()):
                v1 = (d1 or {}).get(k)
                v2 = (d2 or {}).get(k)
                if is_object_val and (isinstance(v1, dict) or isinstance(v2, dict)):
                    v1 = v1 if isinstance(v1, dict) else {}
                    v2 = v2 if isinstance(v2, dict) else {}
                    out_per[k] = {
                        "debit": (v1.get("debit") or 0) + (v2.get("debit") or 0),
                        "credit": (v1.get("credit") or 0) + (v2.get("credit") or 0),
                        "balance": (v1.get("balance") or 0) + (v2.get("balance") or 0),
                        "pl": (v1.get("pl") or 0) + (v2.get("pl") or 0),
                    }
                else:
                    out_per[k] = (v1 if v1 is not None else 0) + (v2 if v2 is not None else 0)
            return out_per
        # Merge duplicate account names: (level1, level2, level3, account_name) so sequence stays correct (expense: detail under Direct/Indirect)
        merged_detail = {}
        for r in detail_rows:
            aname = (r.get("account_name") or "").strip() or "\x00"
            key = (r["level1"], r["level2"], r.get("level3") or "", aname)
            if key not in merged_detail:
                # Keep level1..level5 from first row so sort order is correct (expense detail under Direct/Indirect Expenses)
                merged_detail[key] = {"level1": r["level1"], "level2": r["level2"], "level3": r.get("level3") or "", "level4": r.get("level4") or "", "level5": r.get("level5") or "", "account_name": r["account_name"], "amount": r["amount"], "monthly": dict(r.get("monthly") or {}), "quarterly": dict(r.get("quarterly") or {})}
            else:
                m = merged_detail[key]
                m["amount"] = m["amount"] + r["amount"]
                m["monthly"] = merge_period_dict(m["monthly"], r.get("monthly") or {}, is_object_val=True)
                m["quarterly"] = merge_period_dict(m["quarterly"], r.get("quarterly") or {}, is_object_val=True)
        detail_rows = list(merged_detail.values())

        out = []
        for key in agg:
            d = agg[key]
            pad = list(key) + [""] * (6 - len(key))
            l1 = pad[0] if len(pad) > 0 else ""
            l2 = pad[1] if len(pad) > 1 else ""
            l3 = pad[2] if len(pad) > 2 else ""
            l4 = pad[3] if len(pad) > 3 else ""
            l5 = pad[4] if len(pad) > 4 else ""
            out = out + [{"level1": l1, "level2": l2, "level3": l3, "level4": l4, "level5": l5, "account_name": "", "amount": round(d.get("amount", 0), 0), "monthly": {k: round(v, 0) for k, v in (d.get("monthly") or {}).items()}, "quarterly": {k: round(v, 0) for k, v in (d.get("quarterly") or {}).items()}, "is_subtotal": True}]
        for r in detail_rows:
            out = out + [{"level1": r["level1"], "level2": r["level2"], "level3": r["level3"], "level4": r["level4"], "level5": r["level5"], "account_name": r["account_name"], "amount": round(r["amount"], 0), "monthly": r.get("monthly") or {}, "quarterly": r.get("quarterly") or {}, "is_subtotal": False}]
        out.sort(key=lambda r: (r["level1"], r["level2"], r["level3"], r["level4"], r["level5"], r["account_name"] or "\uffff"))

        # Remove redundant subtotals: (1) same path + single detail same label, or (2) same level1+level2+label and no details at this subtotal's path (so 3-level vs 5-level: only collapse when no extra level).
        def row_key(row):
            return (row.get("level1"), row.get("level2"), row.get("level3"), row.get("level4"), row.get("level5"))
        def subtotal_display_label(row):
            parts = [row.get("level1"), row.get("level2"), row.get("level3"), row.get("level4"), row.get("level5")]
            non_empty = [p for p in parts if (p or "").strip()]
            return (non_empty[-1] or "").strip() if non_empty else ""
        details_by_key = {}
        detail_l1_l2_names = set()
        for r in out:
            if r.get("is_subtotal"):
                continue
            k = row_key(r)
            aname = (r.get("account_name") or "").strip()
            if k not in details_by_key:
                details_by_key[k] = []
            details_by_key[k].append(aname)
            if aname:
                l1 = r.get("level1")
                l2 = r.get("level2")
                detail_l1_l2_names.add((l1, l2, aname))
        to_remove = []
        for i in range(len(out)):
            r = out[i]
            if not r.get("is_subtotal"):
                continue
            label = subtotal_display_label(r)
            if not label:
                continue
            k = row_key(r)
            same_key_details = details_by_key.get(k) or []
            has_same_key_detail = len(same_key_details) > 0
            single_same_label = (len(same_key_details) == 1 and same_key_details[0] == label)
            l1 = r.get("level1")
            l2 = r.get("level2")
            match_l1_l2 = (l1, l2, label) in detail_l1_l2_names
            if single_same_label:
                to_remove.append(i)
            elif match_l1_l2 and not has_same_key_detail:
                to_remove.append(i)
        out = [out[i] for i in range(len(out)) if i not in to_remove]
        return out

    def build_5level_hierarchy_rows_bs(accounts, root_types):
        """Build flat rows for Balance Sheet: one row per account (group and leaf). Group rows get opening/closing = sum of children. Uses path from COA or parent_account."""
        rows_by_acc = {}
        for acc in accounts:
            rt = acc.get("root_type") or ""
            if rt not in root_types:
                continue
            acc_id = acc.get("account") or ""
            path_from_coa = get_parent_path_from_coa(acc_id) if (coa_by_id and acc_id in coa_by_id) else None
            path = path_from_coa if path_from_coa else get_parent_path(acc_id)
            l1 = path[0] if path and path[0] else (rt or "(No Level 1)")
            l2 = path[1] if len(path) > 1 else ""
            l3 = path[2] if len(path) > 2 else ""
            l4 = path[3] if len(path) > 3 else ""
            l5 = path[4] if len(path) > 4 else ""
            aname = path[5] if (len(path) > 5 and path[5]) else (acc.get("account_name") or acc.get("account"))
            is_grp = acc.get("is_group") or 0
            op = acc.get("opening") or 0
            cl = acc.get("closing") or 0
            monthly_raw = acc.get("monthly") or {}
            run = op
            monthly_cum = {}
            for mn in month_names:
                run = run + (monthly_raw.get(mn) or {}).get("balance", 0)
                monthly_cum[mn] = round(run, 0)
            quarterly_cum = {}
            for qn in quarter_names:
                last_mn = None
                for mn in month_names:
                    parts = mn.split("-")
                    if len(parts) >= 2:
                        mnum = month_name_toto_num.get(parts[0].lower()[:3], 1)
                        ynum = 2000 + int(parts[1]) if len(parts[1]) == 2 else int(parts[1])
                        q = (mnum - 1) // 3 + 1
                        if quarter_label(ynum, q) == qn:
                            last_mn = mn
                quarterly_cum[qn] = monthly_cum.get(last_mn, run) if last_mn else run
            rows_by_acc[acc_id] = {
                "account": acc_id, "parent_account": (acc.get("parent_account") or "").strip(),
                "level1": l1, "level2": l2, "level3": l3, "level4": l4, "level5": l5,
                "account_name": aname, "is_group": 1 if is_grp else 0,
                "opening": round(op, 0) if not is_grp else 0,
                "closing": round(cl, 0) if not is_grp else 0,
                "monthly": dict(monthly_cum) if not is_grp else {mn: 0 for mn in month_names},
                "quarterly": dict(quarterly_cum) if not is_grp else {qn: 0 for qn in quarter_names},
            }
        def path_depth(r):
            parts = [r["level1"], r["level2"], r["level3"], r["level4"], r["level5"]]
            return sum(1 for p in parts if (p or "").strip())
        sorted_acc_ids = sorted(rows_by_acc.keys(), key=lambda a: (-path_depth(rows_by_acc[a]), rows_by_acc[a]["level1"] or "", rows_by_acc[a]["level2"] or "", rows_by_acc[a]["level3"] or "", rows_by_acc[a]["level4"] or "", rows_by_acc[a]["level5"] or "", rows_by_acc[a]["account_name"] or ""))
        for acc_id in sorted_acc_ids:
            r = rows_by_acc[acc_id]
            if not r["is_group"]:
                continue
            child_open = 0
            child_close = 0
            child_monthly = {mn: 0 for mn in month_names}
            child_quarterly = {qn: 0 for qn in quarter_names}
            for other_id, other in rows_by_acc.items():
                if (other.get("parent_account") or "") == acc_id:
                    child_open = child_open + (other.get("opening") or 0)
                    child_close = child_close + (other.get("closing") or 0)
                    for mn in month_names:
                        child_monthly[mn] = child_monthly[mn] + (other.get("monthly") or {}).get(mn, 0)
                    for qn in quarter_names:
                        child_quarterly[qn] = child_quarterly[qn] + (other.get("quarterly") or {}).get(qn, 0)
            r["opening"] = round(child_open, 0)
            r["closing"] = round(child_close, 0)
            r["monthly"] = child_monthly
            r["quarterly"] = child_quarterly
        out = []
        for acc_id in sorted(rows_by_acc.keys(), key=lambda a: (rows_by_acc[a]["level1"] or "", rows_by_acc[a]["level2"] or "", rows_by_acc[a]["level3"] or "", rows_by_acc[a]["level4"] or "", rows_by_acc[a]["level5"] or "", rows_by_acc[a]["account_name"] or "\uffff")):
            r = rows_by_acc[acc_id]
            out.append({
                "level1": r["level1"], "level2": r["level2"], "level3": r["level3"], "level4": r["level4"], "level5": r["level5"],
                "account_name": r["account_name"],
                "opening": r["opening"], "closing": r["closing"],
                "monthly": r.get("monthly") or {}, "quarterly": r.get("quarterly") or {},
                "is_subtotal": bool(r["is_group"]), "is_group": r["is_group"],
            })
        return out

    # Income Statement table sequence (order of rows):
    #   1. Sales (Revenue) + income hierarchy (Income > Direct Income > Sales; Indirect Income > Other Income)
    #   2. Total Sales
    #   3. Direct Expenses + direct_expense_hierarchy_rows (Expense > Expenses > Direct Expenses > Manufacturing, Stock, COGS, etc.)
    #   4. Total Direct Expenses
    #   5. Gross Profit (Sales - Direct Expenses)
    #   6. Indirect Expenses + indirect_expense_hierarchy_rows (Expense > Expenses > Indirect Expenses > ...)
    #   7. Total Indirect Expenses
    #   8. Operating Profit (EBIT)
    #   9. Net Profit (Gross Profit - Indirect Expenses)
    # Sort key for hierarchy: (level1, level2, level3, level4, level5, account_name) so expense detail stays under Direct/Indirect.
    income_hierarchy_rows = build_5level_hierarchy_rows(income_accounts, ["Income"], sign_pl=1)
    direct_expense_hierarchy_rows = build_5level_hierarchy_rows(direct_exp, ["Expense"], sign_pl=-1)
    indirect_expense_hierarchy_rows = build_5level_hierarchy_rows(indirect_exp, ["Expense"], sign_pl=-1)

    total_income_pl = sum(r.get("period_pl", 0) for r in income_accounts)
    total_direct_expense_pl = sum(r.get("period_pl", 0) for r in direct_exp)
    total_indirect_expense_pl = sum(r.get("period_pl", 0) for r in indirect_exp)
    gross_profit_pl = total_income_pl + total_direct_expense_pl
    net_profit_pl = total_income_pl + total_direct_expense_pl + total_indirect_expense_pl


    # Operating Profit (EBIT): Gross Profit - Indirect Expenses
    operating_profit_pl = gross_profit_pl + total_indirect_expense_pl
    income_by_month = {mn: sum(r.get("monthly", {}).get(mn, {}).get("pl", 0) for r in income_accounts) for mn in month_names}
    direct_by_month = {mn: sum(r.get("monthly", {}).get(mn, {}).get("pl", 0) for r in direct_exp) for mn in month_names}
    indirect_by_month = {mn: sum(r.get("monthly", {}).get(mn, {}).get("pl", 0) for r in indirect_exp) for mn in month_names}
    gross_by_month = {mn: income_by_month[mn] + direct_by_month[mn] for mn in month_names}
    net_by_month = {mn: income_by_month[mn] + direct_by_month[mn] + indirect_by_month[mn] for mn in month_names}


    operating_by_month = {mn: gross_by_month[mn] + indirect_by_month[mn] for mn in month_names}
    income_by_quarter = {qn: 0 for qn in quarter_names}
    direct_by_quarter = {qn: 0 for qn in quarter_names}
    indirect_by_quarter = {qn: 0 for qn in quarter_names}
    for mn in month_names:
        parts = mn.split("-")
        if len(parts) >= 2:
            mnum = month_name_toto_num.get(parts[0].lower()[:3], 1)
            ynum = 2000 + int(parts[1]) if len(parts[1]) == 2 else int(parts[1])
            q = (mnum - 1) // 3 + 1
            qn = quarter_label(ynum, q)
            if qn in income_by_quarter:
                income_by_quarter[qn] = income_by_quarter[qn] + income_by_month[mn]
                direct_by_quarter[qn] = direct_by_quarter[qn] + direct_by_month[mn]
                indirect_by_quarter[qn] = indirect_by_quarter[qn] + indirect_by_month[mn]
    gross_by_quarter = {qn: income_by_quarter[qn] + direct_by_quarter[qn] for qn in quarter_names}
    net_by_quarter = {qn: income_by_quarter[qn] + direct_by_quarter[qn] + indirect_by_quarter[qn] for qn in quarter_names}


    operating_by_quarter = {qn: gross_by_quarter[qn] + indirect_by_quarter[qn] for qn in quarter_names}
    profit_loss = {
        "income_hierarchy": income_hierarchy,
        "direct_expense_hierarchy": direct_expense_hierarchy,
        "indirect_expense_hierarchy": indirect_expense_hierarchy,
        "income_hierarchy_rows": income_hierarchy_rows,
        "direct_expense_hierarchy_rows": direct_expense_hierarchy_rows,
        "indirect_expense_hierarchy_rows": indirect_expense_hierarchy_rows,
        "total_income": round(total_income_pl, 0),
        "total_direct_expense": round(-total_direct_expense_pl, 0),
        "total_indirect_expense": round(-total_indirect_expense_pl, 0),
        "gross_profit": round(gross_profit_pl, 0),
        "operating_profit": round(operating_profit_pl, 0),
        "net_profit": round(net_profit_pl, 0),
        "income_by_month": {k: round(v, 0) for k, v in income_by_month.items()},
        "direct_by_month": {k: round(v, 0) for k, v in direct_by_month.items()},
        "indirect_by_month": {k: round(v, 0) for k, v in indirect_by_month.items()},
        "gross_by_month": {k: round(v, 0) for k, v in gross_by_month.items()},
        "operating_by_month": {k: round(v, 0) for k, v in operating_by_month.items()},
        "net_by_month": {k: round(v, 0) for k, v in net_by_month.items()},
        "income_by_quarter": {k: round(v, 0) for k, v in income_by_quarter.items()},
        "direct_by_quarter": {k: round(v, 0) for k, v in direct_by_quarter.items()},
        "indirect_by_quarter": {k: round(v, 0) for k, v in indirect_by_quarter.items()},
        "gross_by_quarter": {k: round(v, 0) for k, v in gross_by_quarter.items()},
        "operating_by_quarter": {k: round(v, 0) for k, v in operating_by_quarter.items()},
        "net_by_quarter": {k: round(v, 0) for k, v in net_by_quarter.items()},
    }

    total_assets_opening = sum(r.get("opening", 0) for r in asset_accounts)
    total_assets_closing = sum(r.get("closing", 0) for r in asset_accounts)
    total_liab_opening = sum(r.get("opening", 0) for r in liability_accounts)
    total_liab_closing = sum(r.get("closing", 0) for r in liability_accounts)
    total_equity_opening = sum(r.get("opening", 0) for r in equity_accounts)
    total_equity_closing = sum(r.get("closing", 0) for r in equity_accounts)

    assets_by_month = {}
    liab_by_month = {}
    equity_by_month = {}
    for mn in month_names:
        run_a = total_assets_opening
        run_l = total_liab_opening
        run_e = total_equity_opening
        for mn2 in month_names:
            if month_names.index(mn2) <= month_names.index(mn):
                run_a = run_a + sum(r.get("monthly", {}).get(mn2, {}).get("balance", 0) for r in asset_accounts)
                run_l = run_l + sum(r.get("monthly", {}).get(mn2, {}).get("balance", 0) for r in liability_accounts)
                run_e = run_e + sum(r.get("monthly", {}).get(mn2, {}).get("balance", 0) for r in equity_accounts)
        assets_by_month[mn] = round(run_a, 0)
        liab_by_month[mn] = round(run_l, 0)
        equity_by_month[mn] = round(run_e, 0)

    # Per-component monthly trend for the Liquidity trend table
    cb_acc = [r for r in asset_accounts if (str(r.get("account_type") or "").strip().lower()) in ("bank", "cash")]
    rec_acc = [r for r in asset_accounts if (str(r.get("account_type") or "").strip().lower()) in ("receivable", "receivables")]
    stk_acc = [r for r in asset_accounts if (str(r.get("account_type") or "").strip().lower()) in ("stock", "inventory")]
    pay_acc = [r for r in liability_accounts if (str(r.get("account_type") or "").strip().lower()) in ("payable", "payables", "creditor", "creditors")]
    cb_open = sum(r.get("opening", 0) for r in cb_acc)
    rec_open = sum(r.get("opening", 0) for r in rec_acc)
    stk_open = sum(r.get("opening", 0) for r in stk_acc)
    pay_open = sum(r.get("opening", 0) for r in pay_acc)
    cash_bank_by_month = {}
    receivables_by_month = {}
    stock_by_month = {}
    payables_by_month = {}
    for mn in month_names:
        run_cb = cb_open
        run_rec = rec_open
        run_stk = stk_open
        run_pay = pay_open
        for mn2 in month_names:
            if month_names.index(mn2) <= month_names.index(mn):
                run_cb = run_cb + sum(r.get("monthly", {}).get(mn2, {}).get("balance", 0) for r in cb_acc)
                run_rec = run_rec + sum(r.get("monthly", {}).get(mn2, {}).get("balance", 0) for r in rec_acc)
                run_stk = run_stk + sum(r.get("monthly", {}).get(mn2, {}).get("balance", 0) for r in stk_acc)
                run_pay = run_pay + sum(r.get("monthly", {}).get(mn2, {}).get("balance", 0) for r in pay_acc)
        cash_bank_by_month[mn] = round(run_cb, 0)
        receivables_by_month[mn] = round(run_rec, 0)
        stock_by_month[mn] = round(run_stk, 0)
        payables_by_month[mn] = round(abs(run_pay), 0)

    assets_by_quarter = {}
    liab_by_quarter = {}
    equity_by_quarter = {}
    cash_bank_by_quarter = {}
    receivables_by_quarter = {}
    stock_by_quarter = {}
    payables_by_quarter = {}
    for qn in quarter_names:
        last_month_in_q = None
        for mn in month_names:
            parts = mn.split("-")
            if len(parts) >= 2:
