args = frappe.form_dict
action = (args.get("action") or "get_data").strip().lower()


def to_float(v):
    try:
        return float(v or 0)
    except Exception:
        return 0.0


def to_datetime(v):
    if not v:
        return None
    try:
        return frappe.utils.get_datetime(v)
    except Exception:
        return None


def normalize_employees(raw_value):
    if not raw_value:
        return []
    if isinstance(raw_value, list):
        return [e for e in raw_value if e]

    txt = str(raw_value)
    txt = txt.replace("\n", ",")
    parts = [p.strip() for p in txt.split(",")]
    seen = set()
    out = []
    for p in parts:
        if p and p not in seen:
            seen.add(p)
            out.append(p)
    return out


def ensure_employee_row(doc, employee):
    if not employee:
        return
    for row in (doc.get("employee") or []):
        if row.get("employee") == employee:
            return
    doc.append("employee", {
        "employee": employee,
        "time_in_mins": 0,
        "completed_qty": 0,
    })


def append_time_log(doc, employee, from_time=None, to_time=None, completed_qty=0):
    if not employee:
        frappe.throw("Employee is required.")

    from_dt = to_datetime(from_time) or frappe.utils.now_datetime()
    to_dt = to_datetime(to_time) if to_time else None

    if to_dt and to_dt < from_dt:
        to_dt = from_dt

    time_in_mins = 0
    if to_dt:
        time_in_mins = max(0, ((to_dt - from_dt).total_seconds() / 60.0))

    doc.append("time_logs", {
        "employee": employee,
        "from_time": from_dt,
        "to_time": to_dt,
        "time_in_mins": time_in_mins,
        "completed_qty": to_float(completed_qty),
    })


def apply_control_action(action_name, payload):
    job_card_name = (payload.get("job_card") or "").strip()
    employee = (payload.get("employee") or "").strip()
    from_time = payload.get("from_time")
    to_time = payload.get("to_time")
    completed_qty = to_float(payload.get("completed_qty"))

    if not job_card_name:
        frappe.throw("Job Card is required.")
    if not employee:
        frappe.throw("Employee is required.")

    doc = frappe.get_doc("Job Card", job_card_name)

    if (doc.get("status") or "").lower() in ("cancelled",):
        frappe.throw("Cancelled Job Card cannot be updated.")

    ensure_employee_row(doc, employee)

    if action_name == "start_job_card":
        append_time_log(doc, employee, from_time=from_time, to_time=None, completed_qty=0)
        doc.status = "Work In Progress"
        if doc.meta.has_field("job_started"):
            doc.job_started = 1
        if doc.meta.has_field("started_time"):
            doc.started_time = to_datetime(from_time) or frappe.utils.now_datetime()

    elif action_name == "update_production":
        if completed_qty <= 0:
            frappe.throw("Completed Qty must be greater than 0 for partial production.")
        append_time_log(doc, employee, from_time=from_time, to_time=to_time, completed_qty=completed_qty)
        if (doc.get("status") or "") in ("Open", "Pending", "Material Transferred"):
            doc.status = "Work In Progress"

    elif action_name == "complete_job_card":
        if completed_qty < 0:
            frappe.throw("Completed Qty cannot be negative.")
        append_time_log(doc, employee, from_time=from_time, to_time=to_time, completed_qty=completed_qty)
        doc.status = "Completed"
        if doc.meta.has_field("actual_end_date"):
            doc.actual_end_date = to_datetime(to_time) or frappe.utils.now_datetime()

    doc.save(ignore_permissions=True)
    return {
        "job_card": doc.name,
        "status": doc.status,
        "total_completed_qty": doc.get("total_completed_qty") or 0,
    }


