def build_summary_from_work_orders(work_orders, entity_type, entity_doc, sales_order_items=None):
    wo_names = [w.get("name") for w in work_orders if w.get("name")]

    job_cards = []
    if wo_names:
        job_cards = frappe.get_all(
            "Job Card",
            filters={"work_order": ["in", wo_names]},
            fields=["name", "work_order", "operation", "status", "for_quantity", "total_completed_qty", "bom_no", "item_name", "production_item"],
            order_by="name asc",
            limit_page_length=20000,
        )

    bom_names = list(set([j.get("bom_no") for j in job_cards if j.get("bom_no")]))
    bom_items = []
    if bom_names:
        bom_items = frappe.get_all(
            "BOM Item",
            filters={"parent": ["in", bom_names], "parenttype": "BOM"},
            fields=["parent", "item_code", "item_name", "qty", "uom", "stock_qty"],
            order_by="parent asc, idx asc",
            limit_page_length=50000,
        )

    jc_names = [j.get("name") for j in job_cards if j.get("name")]
    time_logs = []
    if jc_names:
        time_logs = frappe.get_all(
            "Job Card Time Log",
            filters={"parent": ["in", jc_names], "parenttype": "Job Card"},
            fields=["parent", "employee", "completed_qty", "to_time"],
            limit_page_length=50000,
        )

    logs_by_jc = {}
    for t in time_logs:
        p = t.get("parent")
        if not p:
            continue
        if p not in logs_by_jc:
            logs_by_jc[p] = []
        logs_by_jc[p].append(t)

    total_qty = sum([to_float(w.get("qty")) for w in work_orders])
    completed_qty = sum([to_float(w.get("produced_qty")) for w in work_orders])
    remaining_qty = max(total_qty - completed_qty, 0)

    in_process_statuses = ["work in progress", "open", "pending", "material transferred"]
    employee_map = {}

    def add_emp(emp, comp=0, inp=0):
        key = emp or "(No Employee)"
        if key not in employee_map:
            employee_map[key] = {"employee": key, "completed_qty": 0.0, "in_process_qty": 0.0}
        current_completed = to_float(employee_map[key].get("completed_qty"))
        current_in_process = to_float(employee_map[key].get("in_process_qty"))
        employee_map[key]["completed_qty"] = current_completed + to_float(comp)
        employee_map[key]["in_process_qty"] = current_in_process + to_float(inp)

    for t in time_logs:
        add_emp(t.get("employee"), comp=t.get("completed_qty") or 0, inp=0)

    for jc in job_cards:
        st = (jc.get("status") or "").strip().lower()
        if st not in in_process_statuses:
            continue
        jc_qty = to_float(jc.get("total_completed_qty"))
        jc_logs = logs_by_jc.get(jc.get("name"), [])
        jc_employees = list(set([l.get("employee") for l in jc_logs if l.get("employee")]))
        if jc_employees:
            split_qty = jc_qty / len(jc_employees) if len(jc_employees) else 0
            for emp in jc_employees:
                add_emp(emp, comp=0, inp=split_qty)
        else:
            add_emp("(No Employee)", comp=0, inp=jc_qty)

    pp_set = sorted(list(set([w.get("production_plan") for w in work_orders if w.get("production_plan")])))
    so_set = sorted(list(set([w.get("sales_order") for w in work_orders if w.get("sales_order")])))

    jc_total = len(job_cards)
    jc_completed = len([j for j in job_cards if (j.get("status") or "").strip().lower() == "completed"])
    jc_in_process = len([j for j in job_cards if (j.get("status") or "").strip().lower() in in_process_statuses])

    return {
        "entity_type": entity_type,
        "entity_doc": entity_doc,
        "sales_order_items": sales_order_items or [],
        "work_orders": work_orders,
        "sales_orders": so_set,
        "production_plans": pp_set,
        "job_cards": job_cards,
        "bom_items": bom_items,
        "totals": {
            "work_order_total_qty": total_qty,
            "work_order_completed_qty": completed_qty,
            "work_order_remaining_qty": remaining_qty,
            "job_card_total": jc_total,
            "job_card_completed": jc_completed,
            "job_card_in_process": jc_in_process,
        },
        "employee_summary": sorted(
            list(employee_map.values()),
            key=lambda x: (x.get("employee") or "")
        )
    }


