    if not employees:
        frappe.throw("At least one employee is required.")

    total_completed_qty = to_float(args.get("completed_qty"))
    split_qty = 0
    if action in ("update_production", "complete_job_card") and len(employees) > 0:
        split_qty = total_completed_qty / len(employees)

    results = []
    for idx, emp in enumerate(employees):
        emp_qty = 0
        if action in ("update_production", "complete_job_card"):
            if idx == len(employees) - 1:
                emp_qty = total_completed_qty - (split_qty * idx)
            else:
                emp_qty = split_qty

        payload = {
            "job_card": args.get("job_card"),
            "employee": emp,
            "from_time": args.get("from_time"),
            "to_time": args.get("to_time"),
            "completed_qty": emp_qty,
        }
        results.append(apply_control_action(action, payload))

    frappe.db.commit()
    frappe.response["message"] = {
        "ok": True,
        "action": action,
        "job_card": args.get("job_card"),
