# Work Order Operations
operations_by_wo = {}
workstation_set = set()

if wo_names:
    op_filters = {"parent": ["in", wo_names], "parenttype": "Work Order"}
    if workstation:
        op_filters["workstation"] = workstation

    op_rows = frappe.get_all(
