job_cards = sorted(job_cards, key=lambda x: (x.get("posting_date") or "", x.get("name") or ""))

# Time logs (batch)
employee_time_logs = []
if job_cards:
    jc_names = [jc.get("name") for jc in job_cards if jc.get("name")]

    def chunks_list(lst, n=1000):
        for i in range(0, len(lst), n):
            yield lst[i:i+n]

    time_log_rows = []
    # Try parentfield + fallback
    for batch in chunks_list(jc_names, 1000):
        rows = frappe.get_all(
            "Job Card Time Log",
            filters={
                "parent": ["in", batch],
                "parenttype": "Job Card",
            },
            fields=["parent", "employee", "from_time", "to_time", "time_in_mins", "completed_qty", "operation"],
            limit_page_length=100000,
        )
        time_log_rows.extend(rows)
        if len(time_log_rows) >= limit_time_logs:
            time_log_rows = time_log_rows[:limit_time_logs]
            break

    jc_to_wo = {jc["name"]: jc.get("work_order") for jc in job_cards if jc.get("name")}
    jc_details_map = {jc["name"]: jc for jc in job_cards if jc.get("name")}

    for log in time_log_rows:
        job_card = log.get("parent")
        work_order = jc_to_wo.get(job_card, "") or ""
        employee = log.get("employee") or "(No Employee)"
        from_time = log.get("from_time")
        to_time = log.get("to_time")
        time_in_mins = float(log.get("time_in_mins") or 0)
        completed_qty = float(log.get("completed_qty") or 0)

        # Skip empty/zero logs in Employee tab:
        # no timestamps AND both metrics are zero.
        if (not from_time and not to_time and time_in_mins == 0 and completed_qty == 0):
            continue

        jc_details = jc_details_map.get(job_card, {}) or {}
        wo_details = wo_map.get(work_order, {}) if work_order else {}

        employee_time_logs.append({
            "work_order": work_order,
            "job_card": job_card,
            "employee": employee,
            "from_time": from_time,
            "to_time": to_time,
            "time_in_mins": time_in_mins,
            "completed_qty": completed_qty,
            "operation": log.get("operation") or jc_details.get("operation") or "",
            "production_item": wo_details.get("production_item") or jc_details.get("production_item") or "",
            "item_name": wo_details.get("item_name") or jc_details.get("item_name") or "",
            "company": wo_details.get("company") or jc_details.get("company") or "",
        })

# Distinct values for slicers
company_set = set()
prod_item_set = set()
status_set = set()
employee_set = set()

for wo in work_orders:
    if wo.get("company"): company_set.add(wo["company"])
    if wo.get("production_item"): prod_item_set.add(wo["production_item"])
    if wo.get("status"): status_set.add(wo["status"])

for jc in job_cards:
    if jc.get("company"): company_set.add(jc["company"])
    if jc.get("production_item"): prod_item_set.add(jc["production_item"])
    if jc.get("status"): status_set.add(jc["status"])
    if jc.get("workstation"): workstation_set.add(jc["workstation"])

for log in employee_time_logs:
    emp = log.get("employee")
    if emp and emp != "(No Employee)":
        employee_set.add(emp)

distinct_values = {
    "companies": sorted(company_set),
    "production_items": sorted(prod_item_set),
    "statuses": sorted(status_set),
    "workstations": sorted(workstation_set),
    "employees": sorted(employee_set),
    "sales_orders": sorted(list(set([so.get("name") for so in sales_orders if so.get("name")]))),
    "production_plans": sorted(list(set([pp.get("name") for pp in production_plans if pp.get("name")]))),
}

response_data = {
    "work_orders": work_orders,
    "operations_by_wo": operations_by_wo,
    "job_cards": job_cards,
    "employee_time_logs": employee_time_logs,
    "sales_orders": sales_orders,
    "production_plans": production_plans,
    "distinct_values": distinct_values,
    "debug": {
        "caps": {
            "limit_work_orders": limit_work_orders,
            "limit_job_cards": limit_job_cards,
            "limit_time_logs": limit_time_logs,
        },
        "counts": {
            "work_orders": len(work_orders),
            "job_cards": len(job_cards),
            "employee_time_logs": len(employee_time_logs),
        }
    }
}

frappe.response["message"] = response_data
